-- 塗料マスタ再整列(legacy.htmlのPAINTS配列=クライアント真実に合わせる)
-- sort_order = クライアント配列index = レシピの c.i。これで集計の土台が通る。
-- 何度流してもOK。クライアントに無いidは掃除する。

on conflict (id) do update set brand=excluded.brand, code=excluded.code, name=excluded.name, hex=excluded.hex, sort_order=excluded.sort_order;

